import { useState, useEffect } from 'react';
import './Loader.css';

const Loader = () => {
  const [progress, setProgress] = useState(0);
  const [done, setDone] = useState(false);

  useEffect(() => {
  let prog = 0;

  const fill = setInterval(() => {
    prog += Math.random() * 25;

    if (prog >= 100) {
      prog = 100;
      clearInterval(fill);

      setTimeout(() => {
        setDone(true);
      }, 300);
    }

    setProgress(prog);
  }, 120);

  return () => clearInterval(fill);
}, []);

