  return (
    <div id="loader" className={done ? 'done' : ''}>
      <div className="loader-logo">Arthnex</div>
      <div className="loader-bar">
        <div className="loader-fill" style={{ width: `${progress}%` }} />
      </div>
    </div>
  );
};

export default Loader;
